}

// CreateTopic adds a new topic entry to the remote store.
func (s *HTTPStore) CreateTopic(project string, entry TopicEntry) error {
	body, err := json.Marshal(entry)
	if err != nil {
		return fmt.Errorf("plan store: marshal topic: %w", err)
